-- PUS (Premium User Store) Items table
-- Source: MSSQL PUS_ITEMS (137 rows)
-- Each row defines a purchasable item in the cash shop.

CREATE TABLE IF NOT EXISTS pus_items (
    id              INTEGER     NOT NULL PRIMARY KEY,
    item_id         INTEGER     NOT NULL,
    item_name       VARCHAR(150),
    item_title      VARCHAR(1000),
    price           INTEGER     DEFAULT 0,
    send_type       INTEGER     DEFAULT 1,
    buy_count       INTEGER     NOT NULL DEFAULT 1,
    item_desc       VARCHAR(1000) NOT NULL DEFAULT '',
    category        SMALLINT    NOT NULL DEFAULT 1,
    price_type      SMALLINT    NOT NULL DEFAULT 0
);

CREATE INDEX IF NOT EXISTS idx_pus_items_category ON pus_items(category);
CREATE INDEX IF NOT EXISTS idx_pus_items_item_id  ON pus_items(item_id);

-- Seed data from MSSQL PUS_ITEMS (137 rows)
-- price_type: 0 = Knight Cash (KC), 1 = TL (real currency balance)
ON CONFLICT (id) DO NOTHING;
